INSERT INTO transfer_outgoing VALUES(1,'2026-summer',3,'Arsenal','MEDIUM-LOW','아르테타 주도 관심 지속되나 빌라 "매각 의사 없음" 재확인 — 공식 오퍼 없음, 에메리는 콘사를 핵심 자원으로 규정하고 오퍼 자체를 검토하지 않겠다는 입장.','https://readastonvilla.com/2026/07/03/arsenal-konsa-interest-aston-villa-60m-transfer-stance/ , https://thehardtackle.com/transfer-news/2026/07/07/aston-villa-reluctant-to-sell-ezri-konsa-amid-arsenal-links/','3티어 다수(하드태클/리드아스톤빌라)만 보도, 텔레그래프 등 상위 매체 팔로업 없음 — 등급 하향(MEDIUM→MEDIUM-LOW). 2026-07-08 확인.');
INSERT INTO transfer_outgoing VALUES(2,'2026-summer',13,'Arsenal','MEDIUM-HIGH','£130m(요구)/£80m(청취 가능) 밸류. 로마노: 아스날 측 "매우 좋은 진전"(very good progress) — 단, 빌라는 영국 신기록급 이적료 아니면 매각 거부 입장 유지. 2031년 계약이라 매각 압박 없음.','https://www.skysports.com/football/transfer-paper-talk (Sky Sports), https://www.teamtalk.com/arsenal/morgan-rogers-transfer-news-record-bid-imminent-from-arsenal-villa (로마노 인용)','1티어(로마노) "매우 좋은 진전" 보도로 근거 보강 — 등급은 MEDIUM-HIGH 유지(합의/advanced talks 단계 아님). 2026-07-08 확인.');
